// pablo_core.udl — UniFFI interface for pablo-core
// This file defines the Swift/Windows FFI boundary.
// Keep it thin and boring: simple value types, no generics, no closures.

namespace pablo_core {
    string core_version();

    [Async, Throws=PabloError]
    sequence<float> preprocess_pcm(string path, u8 channels, u32 sample_rate);

    [Async, Throws=PabloError]
    sequence<RawSegment> transcribe_audio(string model_path, sequence<float> audio);

    string render_google_meet(TranscriptResult transcript, GoogleMeetOptions opts);

    [Async, Throws=PabloError]
    TranscriptResult transcribe_session_1on1(
        string session_id,
        string mic_path,
        string? system_path,
        TranscriptionConfig config
    );
};

// Unified error type for pablo-core operations.
[Error]
interface PabloError {
    AudioPreprocessing(string message);
    WhisperInit(string message);
    WhisperTranscribe(string message);
    ApiClient(u16 status_code, string message);
    JsonParse(string message);
    Unauthenticated();
    Forbidden();
    NotFound(string resource);
    ConflictState(string message);
};

// Options for rendering to Google Meet format.
dictionary GoogleMeetOptions {
    string session_date;
    string therapist_name;
    string client_name;
    string client_a_name;
    string client_b_name;
};

// Configuration for a local transcription run.
dictionary TranscriptionConfig {
    string model_path;
    u8 mic_channels;
    u32 mic_sample_rate;
    u8 system_channels;
    u32 system_sample_rate;
};

// A raw ASR segment from Whisper. Timestamps are milliseconds.
dictionary RawSegment {
    i64 start_ms;
    i64 end_ms;
    string text;
};

// Who spoke this segment.
enum SpeakerLabel {
    "Therapist",
    "Client",
    "ClientA",
    "ClientB",
    "Unknown",
};

// Whether the session has one or two clients.
enum SessionMode {
    "OneToOne",
    "Couples",
};

// A single speaker turn with start/end timestamps (seconds) and transcript text.
dictionary TranscriptSegment {
    SpeakerLabel speaker;
    double start_seconds;
    double end_seconds;
    string text;
};

// The full transcript for one session.
dictionary TranscriptResult {
    string session_id;
    SessionMode session_mode;
    sequence<TranscriptSegment> segments;
};

// ── Domain types for Pablo API client ────────────────────────────────────────

enum SessionStatus {
    "Scheduled",
    "InProgress",
    "RecordingComplete",
    "Queued",
    "Processing",
    "PendingReview",
    "Finalized",
    "Cancelled",
    "Failed",
};

enum VideoPlatform {
    "Zoom",
    "Teams",
    "Meet",
    "None",
};

enum SessionType {
    "Individual",
    "Couples",
};

enum SessionSource {
    "Web",
    "Companion",
    "Calendar",
};

enum QualityPreset {
    "Fast",
    "Balanced",
    "Accurate",
};

// Minimal patient info embedded in a session.
dictionary PatientSummary {
    string id;
    string first_name;
    string last_name;
};

// A therapy session.
dictionary Session {
    string id;
    string patient_id;
    PatientSummary? patient;
    SessionStatus status;
    string? scheduled_at;
    string? started_at;
    string? ended_at;
    u32 duration_minutes;
    string? video_link;
    VideoPlatform? video_platform;
    SessionType session_type;
    SessionSource source;
    string? notes;
    string created_at;
    string updated_at;
};

// Request body for creating a new session.
dictionary CreateSessionRequest {
    string patient_id;
    string scheduled_at;
    u32? duration_minutes;
    string? video_link;
    VideoPlatform? video_platform;
    SessionType? session_type;
    SessionSource? source;
    string? notes;
};

// Request body for updating an existing session.
dictionary UpdateSessionRequest {
    string? scheduled_at;
    string? video_link;
    VideoPlatform? video_platform;
    u32? duration_minutes;
    string? notes;
};

// Therapist preference settings.
dictionary UserPreferences {
    VideoPlatform default_video_platform;
    SessionType default_session_type;
    u32 default_duration_minutes;
    boolean auto_transcribe;
    QualityPreset quality_preset;
    string therapist_display_name;
};

// User profile from the Pablo backend.
dictionary UserProfile {
    string id;
    string email;
    string first_name;
    string last_name;
    string role;
    string created_at;
};

// BAA acceptance status.
dictionary BaaStatus {
    boolean baa_accepted;
    string? accepted_at;
};

// A patient record.
dictionary Patient {
    string id;
    string user_id;
    string first_name;
    string last_name;
    string? email;
    string? phone;
    string status;
    string? date_of_birth;
    string? diagnosis;
    u32 session_count;
    string? last_session_date;
    string? next_session_date;
    string created_at;
    string updated_at;
};

// Paginated list of sessions.
dictionary SessionListResponse {
    sequence<Session> data;
    u32 total;
    u32 page;
    u32 page_size;
    boolean has_more;
};

// Paginated list of patients.
dictionary PatientListResponse {
    sequence<Patient> data;
    u32 total;
    u32 page;
    u32 page_size;
    boolean has_more;
};

// Response from uploading a transcript.
dictionary TranscriptUploadResponse {
    string id;
    SessionStatus status;
    string message;
};

import Foundation
import os

/// A simple URLSession wrapper for communicating with the sample backend.
@MainActor
final class APIClient {
    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "APIClient")

    nonisolated let baseURL: URL
    private let clientType = "therapyrecorder-macos/1.0"

    /// Optional closure to provide a Bearer token for authenticated requests.
    var getToken: (@Sendable () async throws -> String)?

    init(baseURL: String = "http://localhost:8000") {
        if let error = URLValidator.validateScheme(baseURL) {
            preconditionFailure("APIClient: \(error)")
        }
        guard let url = URL(string: baseURL) else {
            preconditionFailure("APIClient initialized with invalid base URL: \(baseURL)")
        }
        self.baseURL = url
    }

    /// Checks if the backend is reachable.
    func healthCheck() async throws -> Bool {
        let url = baseURL.appendingPathComponent("health")
        var request = URLRequest(url: url)
        request.setValue(clientType, forHTTPHeaderField: "X-Client-Type")
        let (_, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse else { return false }
        return httpResponse.statusCode == 200
    }

    /// Uploads a recording file to the backend via multipart form data.
    /// Returns a progress-reporting async stream and the final upload response.
    func uploadRecording(
        fileURL: URL,
        onProgress: @Sendable @escaping (Double) -> Void
    ) async throws -> UploadResponse {
        let url = baseURL.appendingPathComponent("api/recordings/upload")

        let boundary = UUID().uuidString
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue(
            "multipart/form-data; boundary=\(boundary)",
            forHTTPHeaderField: "Content-Type"
        )
        request.setValue(clientType, forHTTPHeaderField: "X-Client-Type")

        // Inject Bearer token if available
        if let getToken {
            let token = try await getToken()
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        let fileData = try Data(contentsOf: fileURL)
        let body = createMultipartBody(
            fileData: fileData,
            fileName: fileURL.lastPathComponent,
            boundary: boundary
        )
        request.httpBody = body

        logger.info("Uploading \(fileURL.lastPathComponent) (\(fileData.count) bytes)")

        // Simulate incremental progress since URLSession data tasks
        // don't provide upload progress natively without a delegate.
        onProgress(0.3)

        let (data, response) = try await URLSession.shared.data(for: request)

        onProgress(1.0)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let body = String(data: data, encoding: .utf8) ?? "Unknown error"
            logger.error("Upload failed: \(httpResponse.statusCode) — \(body)")
            throw APIError.serverError(statusCode: httpResponse.statusCode, message: body)
        }

        let decoded = try JSONDecoder().decode(UploadResponse.self, from: data)
        logger.info("Upload successful: \(decoded.id)")
        return decoded
    }

    /// Fetches a paginated list of patients from the backend.
    func fetchPatients(
        search: String = "",
        page: Int = 1,
        pageSize: Int = 50
    ) async throws -> PatientListResponse {
        guard var components = URLComponents(
            url: baseURL.appendingPathComponent("api/patients"),
            resolvingAgainstBaseURL: false
        ) else {
            throw APIError.invalidResponse
        }
        components.queryItems = [
            URLQueryItem(name: "search", value: search),
            URLQueryItem(name: "page", value: String(page)),
            URLQueryItem(name: "page_size", value: String(pageSize)),
        ]

        guard let requestURL = components.url else {
            throw APIError.invalidResponse
        }
        var request = URLRequest(url: requestURL)
        request.setValue(clientType, forHTTPHeaderField: "X-Client-Type")

        if let getToken {
            let token = try await getToken()
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let body = String(data: data, encoding: .utf8) ?? "Unknown error"
            logger.error("Fetch patients failed: \(httpResponse.statusCode) — \(body)")
            throw APIError.serverError(statusCode: httpResponse.statusCode, message: body)
        }

        let decoder = JSONDecoder()
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        return try decoder.decode(PatientListResponse.self, from: data)
    }

    func createMultipartBody(
        fileData: Data,
        fileName: String,
        boundary: String
    ) -> Data {
        var body = Data()
        body.append(Data("--\(boundary)\r\n".utf8))
        body.append(Data("Content-Disposition: form-data; name=\"file\"; filename=\"\(fileName)\"\r\n".utf8))
        body.append(Data("Content-Type: application/octet-stream\r\n\r\n".utf8))
        body.append(fileData)
        body.append(Data("\r\n--\(boundary)--\r\n".utf8))
        return body
    }
}

enum APIError: LocalizedError {
    case invalidResponse
    case serverError(statusCode: Int, message: String)

    var errorDescription: String? {
        switch self {
        case .invalidResponse:
            "Invalid response from server."
        case let .serverError(code, message):
            "Server error (\(code)): \(message)"
        }
    }
}

struct UploadResponse: Codable, Sendable {
    let id: String
    let status: String
}

/// Server configuration returned by the therapy-assistant-platform's /api/config endpoint.
struct ServerConfig: Codable, Sendable {
    let apiUrl: String
    let firebaseApiKey: String?
    let firebaseProjectId: String?
}

/// Fetches runtime configuration from the therapy-assistant-platform.
/// This discovers the backend API URL so the user doesn't have to enter it manually.
func fetchServerConfig(authServerURL: String) async throws -> ServerConfig {
    let base = authServerURL.trimmingCharacters(in: CharacterSet(charactersIn: "/"))
    try URLValidator.throwIfInvalid(base)
    guard let url = URL(string: "\(base)/api/config") else {
        throw APIError.invalidResponse
    }
    let (data, response) = try await URLSession.shared.data(from: url)
    guard let httpResponse = response as? HTTPURLResponse,
          (200 ... 299).contains(httpResponse.statusCode)
    else {
        throw APIError.invalidResponse
    }
    return try JSONDecoder().decode(ServerConfig.self, from: data)
}

