  2→// Internal to the crate — NOT exposed via UniFFI.
  3→// All API endpoint functions (tasks 108.3, 108.4) will use this module.
  4→
  5→use reqwest::Client;
  6→use secrecy::{ExposeSecret, SecretString};
  7→
  8→use crate::PabloError;
  9→
 10→/// Client-type header value sent with every request so the backend
 11→/// can distinguish companion traffic from web traffic.
 12→const CLIENT_TYPE_HEADER: &str = "pablo-companion-macos/1.0";
 13→
 14→/// Shared HTTP helper for authenticated Pablo API requests.
 15→///
 16→/// Holds a reusable `reqwest::Client` and the base URL. Each method
 17→/// returns a `RequestBuilder` so callers can chain `.json()`, `.query()`, etc.
 18→/// before `.send()`.
 19→pub(crate) struct ApiClient {
 20→    client: Client,
 21→    base_url: String,
 22→}
 23→
 24→impl ApiClient {
 25→    /// Create a new `ApiClient` pointing at the given base URL
 26→    /// (e.g. `"https://api.pablo.health"`).
 27→    pub fn new(base_url: String) -> Self {
 28→        Self {
 29→            client: Client::new(),
 30→            base_url,
 31→        }
 32→    }
 33→
 34→    /// The base URL this client was configured with.
 35→    pub fn base_url(&self) -> &str {
 36→        &self.base_url
 37→    }
 38→
 39→    /// Build an authenticated GET request.
 40→    pub fn get(&self, path: &str, token: &SecretString) -> reqwest::RequestBuilder {
 41→        self.authenticated_request(reqwest::Method::GET, path, token)
 42→    }
 43→
 44→    /// Build an authenticated POST request.
 45→    pub fn post(&self, path: &str, token: &SecretString) -> reqwest::RequestBuilder {
 46→        self.authenticated_request(reqwest::Method::POST, path, token)
 47→    }
 48→
 49→    /// Build an authenticated PATCH request.
 50→    pub fn patch(&self, path: &str, token: &SecretString) -> reqwest::RequestBuilder {
 51→        self.authenticated_request(reqwest::Method::PATCH, path, token)
 52→    }
 53→
 54→    /// Build an authenticated PUT request.
 55→    pub fn put(&self, path: &str, token: &SecretString) -> reqwest::RequestBuilder {
 56→        self.authenticated_request(reqwest::Method::PUT, path, token)
 57→    }
 58→
 59→    /// Build an unauthenticated GET (for health-check, version, etc.).
 60→    pub fn get_public(&self, path: &str) -> reqwest::RequestBuilder {
 61→        self.client
 62→            .get(format!("{}{}", self.base_url, path))
 63→            .header("X-Client-Type", CLIENT_TYPE_HEADER)
 64→    }
 65→
 66→    // ── private helper ──────────────────────────────────────────────────────
 67→
 68→    fn authenticated_request(
 69→        &self,
 70→        method: reqwest::Method,
 71→        path: &str,
 72→        token: &SecretString,
 73→    ) -> reqwest::RequestBuilder {
 74→        self.client
 75→            .request(method, format!("{}{}", self.base_url, path))
 76→            .header(
 77→                "Authorization",
 78→                format!("Bearer {}", token.expose_secret()),
 79→            )
 80→            .header("X-Client-Type", CLIENT_TYPE_HEADER)
 81→    }
 82→}
 83→
 84→/// Map a non-success HTTP response to the appropriate `PabloError` variant.
 85→///
 86→/// The Pablo backend returns JSON error bodies like:
 87→/// ```json
 88→/// { "detail": "...", "error_code": "...", "field": "..." }
 89→/// ```
 90→/// For now we pass the raw body as the error message; structured parsing
 91→/// can be added later when the backend error contract stabilises.
 92→pub(crate) async fn handle_error_response(response: reqwest::Response) -> PabloError {
 93→    let status = response.status().as_u16();
 94→
 95→    match status {
 96→        401 => PabloError::Unauthenticated,
 97→        403 => PabloError::Forbidden,
 98→        404 => {
 99→            let body = response.text().await.unwrap_or_default();
100→            PabloError::NotFound { resource: body }
101→        }
102→        409 => {
103→            let body = response.text().await.unwrap_or_default();
104→            PabloError::ConflictState { message: body }
105→        }
106→        _ => {
107→            let body = response.text().await.unwrap_or_default();
108→            PabloError::ApiClient {
109→                status_code: status,
110→                message: body,
111→            }
112→        }
113→    }
114→}
