197→        SettingsView(
198→            backendURL: $uploadVM.backendURL,
199→            authServerURL: $authVM.authServerURL,
200→            selectedMicID: $recordingVM.selectedMicID,
201→            encryptionEnabled: $recordingVM.encryptionEnabled,
202→            debugEnableMic: $recordingVM.debugEnableMic,
203→            debugEnableSystem: $recordingVM.debugEnableSystem,
204→            userEmail: authVM.authenticatedEmail,
205→            availableMics: recordingVM.availableMics,
206→            isBackendReachable: uploadVM.isBackendReachable,
207→            bluetoothRoutingConflict: recordingVM.bluetoothRoutingConflict,
208→            bluetoothRecommendation: recordingVM.bluetoothRecommendation,
209→            systemAudioPermitted: recordingVM.systemAudioPermitted,
210→            recordingState: recordingVM.recordingState,
211→            diagnostics: recordingVM.debugDiagnostics,
212→            onCheckHealth: {
213→                Task { await uploadVM.checkBackendHealth() }
214→            },
215→            onGenerateTestTone: {
216→                recordingVM.generateTestTone()
217→            },
218→            onSignOut: {
219→                authVM.signOut()
220→            }
221→        )
222→        .tabItem {
223→            Label("Settings", systemImage: "gear")
224→        }
225→        .tag(2)
226→    }
227→}
