   1→// HTTP infrastructure layer for the Pablo API.
   2→// ApiClient struct is internal; public endpoint functions are exposed via UniFFI.
   3→
   4→use reqwest::Client;
   5→use secrecy::{ExposeSecret, SecretString};
   6→
   7→use crate::models::{
   8→    BaaStatus, CreateSessionRequest, Patient, PatientListResponse, Session, SessionListResponse,
   9→    SessionStatus, TranscriptUploadResponse, UpdateSessionRequest, UploadResponse, UserPreferences,
  10→    UserProfile,
  11→};
  12→use crate::PabloError;
  13→
  14→/// Client-type header value sent with every request so the backend
  15→/// can distinguish companion traffic from web traffic.
  16→const CLIENT_TYPE_HEADER: &str = "pablo-companion-macos/1.0";
  17→
  18→/// Shared HTTP helper for authenticated Pablo API requests.
  19→///
  20→/// Holds a reusable `reqwest::Client` and the base URL. Each method
  21→/// returns a `RequestBuilder` so callers can chain `.json()`, `.query()`, etc.
  22→/// before `.send()`.
  23→pub(crate) struct ApiClient {
  24→    client: Client,
  25→    base_url: String,
  26→}
  27→
  28→impl ApiClient {
  29→    /// Create a new `ApiClient` pointing at the given base URL
  30→    /// (e.g. `"https://api.pablo.health"`).
  31→    pub fn new(base_url: String) -> Self {
  32→        Self {
  33→            client: Client::new(),
  34→            base_url,
  35→        }
  36→    }
  37→
  38→    /// The base URL this client was configured with.
  39→    #[cfg(test)]
  40→    pub fn base_url(&self) -> &str {
  41→        &self.base_url
  42→    }
  43→
  44→    /// Build an authenticated GET request.
  45→    pub fn get(&self, path: &str, token: &SecretString) -> reqwest::RequestBuilder {
  46→        self.authenticated_request(reqwest::Method::GET, path, token)
  47→    }
  48→
  49→    /// Build an authenticated POST request.
  50→    pub fn post(&self, path: &str, token: &SecretString) -> reqwest::RequestBuilder {
  51→        self.authenticated_request(reqwest::Method::POST, path, token)
  52→    }
  53→
  54→    /// Build an authenticated PATCH request.
  55→    pub fn patch(&self, path: &str, token: &SecretString) -> reqwest::RequestBuilder {
  56→        self.authenticated_request(reqwest::Method::PATCH, path, token)
  57→    }
  58→
  59→    /// Build an authenticated PUT request.
  60→    pub fn put(&self, path: &str, token: &SecretString) -> reqwest::RequestBuilder {
  61→        self.authenticated_request(reqwest::Method::PUT, path, token)
  62→    }
  63→
  64→    /// Build an unauthenticated GET (for health-check, version, etc.).
  65→    pub fn get_public(&self, path: &str) -> reqwest::RequestBuilder {
  66→        self.client
  67→            .get(format!("{}{}", self.base_url, path))
  68→            .header("X-Client-Type", CLIENT_TYPE_HEADER)
  69→    }
  70→
  71→    // ── private helper ──────────────────────────────────────────────────────
  72→
  73→    fn authenticated_request(
  74→        &self,
  75→        method: reqwest::Method,
  76→        path: &str,
  77→        token: &SecretString,
  78→    ) -> reqwest::RequestBuilder {
  79→        self.client
  80→            .request(method, format!("{}{}", self.base_url, path))
  81→            .header(
  82→                "Authorization",
  83→                format!("Bearer {}", token.expose_secret()),
  84→            )
  85→            .header("X-Client-Type", CLIENT_TYPE_HEADER)
  86→    }
  87→}
  88→
  89→/// Map a non-success HTTP response to the appropriate `PabloError` variant.
  90→///
  91→/// The Pablo backend returns JSON error bodies like:
  92→/// ```json
  93→/// { "detail": "...", "error_code": "...", "field": "..." }
  94→/// ```
  95→/// For now we pass the raw body as the error message; structured parsing
  96→/// can be added later when the backend error contract stabilises.
  97→pub(crate) async fn handle_error_response(response: reqwest::Response) -> PabloError {
  98→    let status = response.status().as_u16();
  99→
 100→    match status {
 101→        401 => PabloError::Unauthenticated,
 102→        403 => PabloError::Forbidden,
 103→        404 => {
 104→            let body = response.text().await.unwrap_or_default();
 105→            PabloError::NotFound { resource: body }
 106→        }
 107→        409 => {
 108→            let body = response.text().await.unwrap_or_default();
 109→            PabloError::ConflictState { message: body }
 110→        }
 111→        _ => {
 112→            let body = response.text().await.unwrap_or_default();
 113→            PabloError::ApiClient {
 114→                status_code: status,
 115→                message: body,
 116→            }
 117→        }
 118→    }
 119→}
