 121→// ── Public endpoint functions ────────────────────────────────────────────────
 122→// These are the public API that gets exposed via UniFFI.
 123→// Each function creates its own ApiClient (stateless, cheap).
 124→// Token is accepted as `String` at the boundary and wrapped in `SecretString`
 125→// internally so sensitive data is protected in Rust memory.
 126→
 127→// ── Group A: Ported from Swift APIClient (108.3) ────────────────────────────
 128→
 129→/// Check that the Pablo backend is reachable. Unauthenticated.
 130→pub async fn health_check(base_url: String) -> Result<(), PabloError> {
 131→    let client = ApiClient::new(base_url);
 132→
 133→    let response = client
 134→        .get_public("/health")
 135→        .send()
 136→        .await
 137→        .map_err(|e| PabloError::ApiClient {
 138→            status_code: 0,
 139→            message: e.to_string(),
 140→        })?;
 141→
 142→    if !response.status().is_success() {
 143→        return Err(handle_error_response(response).await);
 144→    }
 145→
 146→    Ok(())
 147→}
