 149→/// Fetch a paginated list of patients, optionally filtered by search term.
 150→pub async fn fetch_patients(
 151→    base_url: String,
 152→    token: String,
 153→    search: Option<String>,
 154→    page: u32,
 155→    page_size: u32,
 156→) -> Result<PatientListResponse, PabloError> {
 157→    let client = ApiClient::new(base_url);
 158→    let token = SecretString::from(token);
 159→
 160→    let mut query_params: Vec<(&str, String)> = vec![
 161→        ("page", page.to_string()),
 162→        ("page_size", page_size.to_string()),
 163→    ];
 164→    if let Some(ref s) = search {
 165→        query_params.push(("search", s.clone()));
 166→    }
 167→
 168→    let response = client
 169→        .get("/api/patients", &token)
 170→        .query(&query_params)
 171→        .send()
 172→        .await
 173→        .map_err(|e| PabloError::ApiClient {
 174→            status_code: 0,
 175→            message: e.to_string(),
 176→        })?;
 177→
 178→    if !response.status().is_success() {
 179→        return Err(handle_error_response(response).await);
 180→    }
 181→
 182→    response
 183→        .json::<PatientListResponse>()
 184→        .await
 185→        .map_err(|e| PabloError::JsonParse {
 186→            message: e.to_string(),
 187→        })
 188→}
