 63→// MARK: - ModelManager
 64→
 65→/// Manages Whisper model files for local transcription.
 66→/// Resolves model paths from the app's Application Support directory or the app bundle.
 67→@MainActor
 68→final class ModelManager: ObservableObject {
 69→    static let shared = ModelManager()
 70→
 71→    @Published var downloadProgress: [QualityPreset: Double] = [:]
 72→    @Published var downloadingPresets: Set<QualityPreset> = []
 73→
 74→    private let fileManager = FileManager.default
 75→    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "ModelManager")
 76→
 77→    private var modelsDirectory: URL {
 78→        let appSupport = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask)[0]
 79→        let dir = appSupport
 80→            .appendingPathComponent("PabloCompanion", isDirectory: true)
 81→            .appendingPathComponent("Models", isDirectory: true)
 82→        try? fileManager.createDirectory(at: dir, withIntermediateDirectories: true)
 83→        return dir
 84→    }
 85→
 86→    /// Returns the URL to the model file for the given preset.
 87→    /// Checks the models directory first, then the app bundle.
 88→    func modelURL(for preset: QualityPreset) throws -> URL {
 89→        // Check Application Support models directory first
 90→        let cachedURL = modelsDirectory.appendingPathComponent(preset.modelFileName)
 91→        if fileManager.fileExists(atPath: cachedURL.path) {
 92→            logger.debug("Found model in cache: \(preset.modelFileName)")
 93→            return cachedURL
 94→        }
 95→
 96→        // Fall back to app bundle
 97→        let name = (preset.modelFileName as NSString).deletingPathExtension
 98→        let ext = (preset.modelFileName as NSString).pathExtension
 99→        if let bundledURL = Bundle.main.url(forResource: name, withExtension: ext) {
100→            logger.debug("Found model in bundle: \(preset.modelFileName)")
101→            return bundledURL
102→        }
103→
104→        logger.warning("Model not found: \(preset.modelFileName)")
105→        throw ModelError.notFound(preset)
106→    }
107→
108→    /// Whether the model for this preset is available (cached or bundled).
109→    func isAvailable(_ preset: QualityPreset) -> Bool {
110→        (try? modelURL(for: preset)) != nil
111→    }
112→
113→    /// Downloads the model for the given preset from the Hugging Face whisper.cpp repository.
114→    /// Progress is published via `downloadProgress` and `downloadingPresets`.
115→    func downloadModel(_ preset: QualityPreset) async throws {
116→        guard !downloadingPresets.contains(preset) else { return }
117→
118→        let baseURL = "https://huggingface.co/ggerganov/whisper.cpp/resolve/main/"
119→        guard let url = URL(string: baseURL + preset.modelFileName) else { return }
120→
121→        downloadingPresets.insert(preset)
122→        downloadProgress[preset] = 0
123→        defer {
124→            downloadingPresets.remove(preset)
125→            downloadProgress.removeValue(forKey: preset)
126→        }
127→
128→        let delegate = ModelDownloadDelegate { [weak self] progress in
129→            Task { @MainActor [weak self] in
130→                self?.downloadProgress[preset] = progress
131→            }
132→        }
133→
134→        do {
135→            let (tempURL, _) = try await URLSession.shared.download(from: url, delegate: delegate)
136→            let destination = modelsDirectory.appendingPathComponent(preset.modelFileName)
137→            if fileManager.fileExists(atPath: destination.path) {
138→                try fileManager.removeItem(at: destination)
139→            }
140→            try fileManager.moveItem(at: tempURL, to: destination)
141→            logger.info("Model downloaded: \(preset.modelFileName)")
142→        } catch {
143→            logger.error("Model download failed for \(preset.modelFileName): \(error.localizedDescription)")
144→            throw ModelError.downloadFailed(error.localizedDescription)
145→        }
146→    }
147→}
148→
149→// MARK: - ModelDownloadDelegate
150→
151→private final class ModelDownloadDelegate: NSObject, URLSessionDownloadDelegate {
152→    private let onProgress: (Double) -> Void
153→
154→    init(onProgress: @escaping (Double) -> Void) {
155→        self.onProgress = onProgress
156→    }
157→
158→    /// Required by URLSessionDownloadDelegate.
159→    /// The async/await wrapper owns the temp file — this is intentionally a no-op.
160→    func urlSession(_: URLSession, downloadTask _: URLSessionDownloadTask, didFinishDownloadingTo _: URL) {}
161→
162→    func urlSession(
163→        _: URLSession,
164→        downloadTask _: URLSessionDownloadTask,
165→        didWriteData _: Int64,
166→        totalBytesWritten: Int64,
167→        totalBytesExpectedToWrite: Int64
168→    ) {
169→        guard totalBytesExpectedToWrite > 0 else { return }
170→        onProgress(Double(totalBytesWritten) / Double(totalBytesExpectedToWrite))
171→    }
172→}
