 5→/// Manages fetching and displaying the patient list from the backend.
 6→@MainActor
 7→@Observable
 8→final class PatientViewModel {
 9→    var patients: [Patient] = []
10→    var isLoading = false
11→    var errorMessage: String?
12→    var showError = false
13→    var searchText = ""
14→
15→    var backendURL = "http://localhost:8000" {
16→        didSet {
17→            if URLValidator.validateScheme(backendURL) == nil {
18→                apiClient = APIClient(baseURL: backendURL)
19→            }
20→        }
21→    }
22→
23→    private var apiClient: APIClient
24→    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "PatientViewModel")
25→
26→    init() {
27→        self.apiClient = APIClient()
28→    }
29→
30→    /// Configures the API client with a token provider for authenticated requests.
31→    func configureAuth(getToken: @escaping @Sendable () async throws -> String) {
32→        apiClient = APIClient(baseURL: backendURL)
33→        apiClient.getToken = getToken
34→    }
35→
36→    /// Debug status visible in the UI during development.
37→    var debugStatus = ""
38→
39→    func loadPatients() async {
40→        guard apiClient.getToken != nil else {
41→            debugStatus = "Waiting for auth..."
42→            return
43→        }
44→        debugStatus = "Loading from \(apiClient.baseURL)..."
45→        isLoading = true
46→        defer { isLoading = false }
47→
48→        do {
49→            let response = try await apiClient.fetchPatients(search: searchText)
50→            patients = response.data
51→            debugStatus = "Loaded \(response.data.count) of \(response.total) patients"
52→            logger.info("Loaded \(response.data.count) of \(response.total) patients")
53→        } catch {
54→            debugStatus = "Error: \(error.localizedDescription)"
55→            logger.error("Failed to load patients: \(error.localizedDescription)")
56→            errorMessage = "Failed to load patients: \(error.localizedDescription)"
57→            showError = true
58→        }
59→    }
60→}
