  3→/// Main view combining recording controls, recording list, and settings.
  4→struct ContentView: View {
  5→    @State private var authVM = AuthViewModel()
  6→    @State private var recordingVM = RecordingViewModel()
  7→    @State private var uploadVM = UploadViewModel()
  8→    @State private var patientVM = PatientViewModel()
  9→    @State private var transcriptionVM = TranscriptionViewModel()
 10→    @State private var viewingTranscript: TranscriptViewerItem?
 11→    @State private var selectedTab = 0
 12→
 13→    var body: some View {
 14→        Group {
 15→            switch authVM.authState {
 16→            case .unauthenticated, .authenticating, .tokenExpired:
 17→                LoginView(authViewModel: authVM)
 18→                    .frame(minWidth: 500, minHeight: 600)
 19→
 20→            case .authenticated:
 21→                authenticatedContent
 22→            }
 23→        }
 24→        .background(Color.pabloCream)
 25→        .preferredColorScheme(.light)
 26→    }
 27→
 28→    private var authenticatedContent: some View {
 29→        TabView(selection: $selectedTab) {
 30→            recorderTab
 31→            patientsTab
 32→            settingsTab
 33→        }
 34→        .frame(minWidth: 500, minHeight: 600)
 35→        .task {
 36→            // Discover backend URL from the auth server's /api/config.
 37→            // Read auth server URL from Keychain (source of truth) since
 38→            // @AppStorage doesn't persist reliably with @Observable.
 39→            let serverURL = KeychainManager.getToken(forKey: .authServerURL)
 40→                ?? authVM.authServerURL
 41→            if let config = try? await fetchServerConfig(
 42→                authServerURL: serverURL
 43→            ) {
 44→                uploadVM.backendURL = config.apiUrl
 45→                patientVM.backendURL = config.apiUrl
 46→                if KeychainManager.getToken(forKey: .firebaseAPIKey) == nil {
 47→                    if let key = config.firebaseApiKey, !key.isEmpty {
 48→                        KeychainManager.saveToken(key, forKey: .firebaseAPIKey)
 49→                    }
 50→                }
 51→            }
 52→
 53→            // Wire up token injection for authenticated requests
 54→            uploadVM.configureAuth { [authVM] in
 55→                try await authVM.getValidToken()
 56→            }
 57→            patientVM.configureAuth { [authVM] in
 58→                try await authVM.getValidToken()
 59→            }
 60→
 61→            // Eagerly refresh token on startup to catch expired sessions early
 62→            do {
 63→                _ = try await authVM.getValidToken()
 64→            } catch {
 65→                authVM.signOut()
 66→            }
 67→
 68→            // Load patients now that auth is configured
 69→            await patientVM.loadPatients()
 70→            await recordingVM.loadAudioSources()
 71→            await uploadVM.checkBackendHealth()
 72→
 73→            // Configure transcription VM with backend + auth
 74→            transcriptionVM.backendURL = uploadVM.backendURL
 75→            transcriptionVM.getToken = { [authVM] in try await authVM.getValidToken() }
 76→
 77→            // Retry any transcripts that failed to upload last session
 78→            await transcriptionVM.retryPendingUploads()
 79→        }
 80→        .alert(
 81→            "Recording Error",
 82→            isPresented: $recordingVM.showError,
 83→            presenting: recordingVM.errorMessage
 84→        ) { _ in
 85→            Button("OK") {}
 86→        } message: { message in
 87→            Text(message)
 88→        }
 89→        .alert(
 90→            "Upload Error",
 91→            isPresented: $uploadVM.showError,
 92→            presenting: uploadVM.errorMessage
 93→        ) { _ in
 94→            Button("OK") {}
 95→        } message: { message in
 96→            Text(message)
 97→        }
 98→        .alert(
 99→            "Patient Error",
100→            isPresented: $patientVM.showError,
101→            presenting: patientVM.errorMessage
102→        ) { _ in
103→            Button("OK") {}
104→        } message: { message in
105→            Text(message)
106→        }
107→        .onChange(of: uploadVM.backendURL) { _, newURL in
108→            patientVM.backendURL = newURL
109→        }
110→    }
111→
112→    private var recorderTab: some View {
113→        VStack(spacing: 0) {
114→            RecordingControlsView(
115→                state: recordingVM.recordingState,
116→                duration: recordingVM.duration,
117→                micLevel: recordingVM.micLevel,
118→                systemLevel: recordingVM.systemLevel,
119→                systemAudioActive: recordingVM.systemAudioActive,
