34→    func checkBackendHealth() async {
35→        do {
36→            isBackendReachable = try await apiClient.healthCheck()
37→            logger.info("Backend health check: \(self.isBackendReachable ? "OK" : "FAILED")")
38→        } catch {
39→            isBackendReachable = false
40→            logger.warning("Backend unreachable: \(error.localizedDescription)")
41→        }
42→    }
43→
44→    func uploadRecording(
45→        _ recording: LocalRecording,
46→        onComplete: @escaping (UUID) -> Void
47→    ) async {
48→        guard !uploadingRecordingIDs.contains(recording.id) else { return }
49→
50→        uploadingRecordingIDs.insert(recording.id)
51→        uploadProgress[recording.id] = 0.0
52→        logger.info("Starting upload for \(recording.id)")
53→
54→        do {
55→            _ = try await apiClient.uploadRecording(
56→                fileURL: recording.fileURL
57→            ) { [weak self] progress in
58→                Task { @MainActor in
59→                    self?.uploadProgress[recording.id] = progress
60→                }
61→            }
62→
63→            uploadProgress[recording.id] = 1.0
64→            uploadingRecordingIDs.remove(recording.id)
65→            onComplete(recording.id)
66→            logger.info("Upload complete for \(recording.id)")
67→        } catch {
68→            uploadingRecordingIDs.remove(recording.id)
69→            uploadProgress.removeValue(forKey: recording.id)
70→            logger.error("Upload failed for \(recording.id): \(error.localizedDescription)")
71→            errorMessage = "Upload failed: \(error.localizedDescription)"
72→            showError = true
73→        }
74→    }
75→}
