 190→/// Upload a recording file to the backend via multipart form data.
 191→pub async fn upload_recording(
 192→    base_url: String,
 193→    token: String,
 194→    file_path: String,
 195→) -> Result<UploadResponse, PabloError> {
 196→    let client = ApiClient::new(base_url);
 197→    let token = SecretString::from(token);
 198→
 199→    let file_bytes = tokio::fs::read(&file_path)
 200→        .await
 201→        .map_err(|e| PabloError::ApiClient {
 202→            status_code: 0,
 203→            message: format!("Failed to read file: {e}"),
 204→        })?;
 205→
 206→    let file_name = std::path::Path::new(&file_path)
 207→        .file_name()
 208→        .unwrap_or_default()
 209→        .to_string_lossy()
 210→        .to_string();
 211→
 212→    let part = reqwest::multipart::Part::bytes(file_bytes)
 213→        .file_name(file_name)
 214→        .mime_str("application/octet-stream")
 215→        .map_err(|e| PabloError::ApiClient {
 216→            status_code: 0,
 217→            message: e.to_string(),
 218→        })?;
 219→
 220→    let form = reqwest::multipart::Form::new().part("file", part);
 221→
 222→    let response = client
 223→        .post("/api/recordings/upload", &token)
 224→        .multipart(form)
 225→        .send()
 226→        .await
 227→        .map_err(|e| PabloError::ApiClient {
 228→            status_code: 0,
 229→            message: e.to_string(),
 230→        })?;
 231→
 232→    if !response.status().is_success() {
 233→        return Err(handle_error_response(response).await);
 234→    }
 235→
 236→    response
 237→        .json::<UploadResponse>()
 238→        .await
 239→        .map_err(|e| PabloError::JsonParse {
 240→            message: e.to_string(),
 241→        })
 242→}
