  1→import SwiftUI
  2→
  3→/// Main view combining recording controls, recording list, and settings.
  4→struct ContentView: View {
  5→    @State private var authVM = AuthViewModel()
  6→    @State private var recordingVM = RecordingViewModel()
  7→    @State private var uploadVM = UploadViewModel()
  8→    @State private var patientVM = PatientViewModel()
  9→    @State private var transcriptionVM = TranscriptionViewModel()
 10→    @State private var viewingTranscript: TranscriptViewerItem?
 11→    @State private var selectedTab = 0
 12→
 13→    var body: some View {
 14→        Group {
 15→            switch authVM.authState {
 16→            case .unauthenticated, .authenticating, .tokenExpired:
 17→                LoginView(authViewModel: authVM)
 18→                    .frame(minWidth: 500, minHeight: 600)
 19→
 20→            case .authenticated:
 21→                authenticatedContent
 22→            }
 23→        }
 24→        .background(Color.pabloCream)
 25→        .preferredColorScheme(.light)
 26→    }
 27→
 28→    private var authenticatedContent: some View {
 29→        TabView(selection: $selectedTab) {
 30→            recorderTab
 31→            patientsTab
 32→            settingsTab
 33→        }
 34→        .frame(minWidth: 500, minHeight: 600)
 35→        .task {
 36→            // Discover backend URL from the auth server's /api/config.
 37→            // Read auth server URL from Keychain (source of truth) since
 38→            // @AppStorage doesn't persist reliably with @Observable.
 39→            let serverURL = KeychainManager.getToken(forKey: .authServerURL)
 40→                ?? authVM.authServerURL
 41→            if let config = try? await fetchServerConfig(
 42→                authServerURL: serverURL
 43→            ) {
 44→                uploadVM.backendURL = config.apiUrl
 45→                patientVM.backendURL = config.apiUrl
 46→                if KeychainManager.getToken(forKey: .firebaseAPIKey) == nil {
 47→                    if let key = config.firebaseApiKey, !key.isEmpty {
 48→                        KeychainManager.saveToken(key, forKey: .firebaseAPIKey)
 49→                    }
 50→                }
 51→            }
 52→
 53→            // Wire up token injection for authenticated requests
 54→            uploadVM.configureAuth { [authVM] in
 55→                try await authVM.getValidToken()
 56→            }
 57→            patientVM.configureAuth { [authVM] in
 58→                try await authVM.getValidToken()
 59→            }
 60→
 61→            // Eagerly refresh token on startup to catch expired sessions early
 62→            do {
 63→                _ = try await authVM.getValidToken()
 64→            } catch {
 65→                authVM.signOut()
 66→            }
 67→
 68→            // Load patients now that auth is configured
 69→            await patientVM.loadPatients()
 70→            await recordingVM.loadAudioSources()
 71→            await uploadVM.checkBackendHealth()
 72→
 73→            // Configure transcription VM with backend + auth
 74→            transcriptionVM.backendURL = uploadVM.backendURL
 75→            transcriptionVM.configureAuth { [authVM] in
 76→                try await authVM.getValidToken()
 77→            }
 78→
 79→            // Retry any transcripts that failed to upload last session
 80→            await transcriptionVM.retryPendingUploads()
 81→        }
 82→        .alert(
 83→            "Recording Error",
 84→            isPresented: $recordingVM.showError,
 85→            presenting: recordingVM.errorMessage
 86→        ) { _ in
 87→            Button("OK") {}
 88→        } message: { message in
 89→            Text(message)
 90→        }
 91→        .alert(
 92→            "Upload Error",
 93→            isPresented: $uploadVM.showError,
 94→            presenting: uploadVM.errorMessage
 95→        ) { _ in
 96→            Button("OK") {}
 97→        } message: { message in
 98→            Text(message)
 99→        }
100→        .alert(
101→            "Patient Error",
102→            isPresented: $patientVM.showError,
103→            presenting: patientVM.errorMessage
104→        ) { _ in
105→            Button("OK") {}
106→        } message: { message in
107→            Text(message)
108→        }
109→        .onChange(of: uploadVM.backendURL) { _, newURL in
110→            patientVM.backendURL = newURL
111→        }
112→    }
113→
114→    private var recorderTab: some View {
115→        VStack(spacing: 0) {
116→            RecordingControlsView(
117→                state: recordingVM.recordingState,
118→                duration: recordingVM.duration,
119→                micLevel: recordingVM.micLevel,
120→                systemLevel: recordingVM.systemLevel,
121→                systemAudioActive: recordingVM.systemAudioActive,
122→                onStart: {
123→                    Task { await recordingVM.startRecording() }
124→                },
125→                onPause: { recordingVM.pauseRecording() },
126→                onResume: { recordingVM.resumeRecording() },
127→                onStop: {
128→                    Task { await recordingVM.stopRecording() }
129→                }
130→            )
131→
132→            Divider()
133→
134→            recordingList
135→        }
136→        .background(Color.pabloCream)
137→        .tabItem {
138→            Label("Recorder", systemImage: "waveform")
139→        }
140→        .tag(0)
141→    }
142→
143→    private var recordingList: some View {
144→        RecordingListView(
145→            recordings: recordingVM.recordings,
146→            uploadProgress: uploadVM.uploadProgress,
147→            uploadingIDs: uploadVM.uploadingRecordingIDs,
148→            playingRecordingID: recordingVM.playingRecordingID,
149→            transcriptionStates: transcriptionVM.states,
150→            onUpload: { recording in
151→                Task {
152→                    await uploadVM.uploadRecording(recording) { uploadedID in
153→                        if let index = recordingVM.recordings.firstIndex(
154→                            where: { $0.id == uploadedID }
155→                        ) {
156→                            recordingVM.recordings[index].isUploaded = true
157→                        }
158→                    }
159→                }
160→            },
161→            onPlay: { recording in
162→                recordingVM.playRecording(recording)
163→            },
164→            onStopPlayback: {
165→                recordingVM.stopPlayback()
166→            },
167→            onViewTranscript: { recording in
168→                if let text = transcriptionVM.states[recording.id]?.transcript {
169→                    viewingTranscript = TranscriptViewerItem(
170→                        id: recording.id,
171→                        text: text,
172→                        recordingDate: recording.createdAt
173→                    )
174→                }
175→            },
176→            onTranscribe: { recording in
177→                Task { await transcriptionVM.transcribe(recording) }
178→            }
179→        )
180→        .sheet(item: $viewingTranscript) { (item: TranscriptViewerItem) in
181→            TranscriptViewerView(transcript: item.text, recordingDate: item.recordingDate)
182→        }
183→        .task {
184→            recordingVM.onRecordingCompleted = { recording in
185→                transcriptionVM.transcribeIfNeeded(recording)
186→            }
187→        }
188→    }
189→
190→    private var patientsTab: some View {
191→        PatientListView(viewModel: patientVM)
192→            .tabItem {
193→                Label("Patients", systemImage: "person.2")
194→            }
195→            .tag(1)
196→    }
197→
198→    private var settingsTab: some View {
199→        SettingsView(
200→            backendURL: $uploadVM.backendURL,
201→            authServerURL: $authVM.authServerURL,
202→            selectedMicID: $recordingVM.selectedMicID,
203→            encryptionEnabled: $recordingVM.encryptionEnabled,
204→            debugEnableMic: $recordingVM.debugEnableMic,
205→            debugEnableSystem: $recordingVM.debugEnableSystem,
206→            userEmail: authVM.authenticatedEmail,
207→            availableMics: recordingVM.availableMics,
208→            isBackendReachable: uploadVM.isBackendReachable,
209→            bluetoothRoutingConflict: recordingVM.bluetoothRoutingConflict,
210→            bluetoothRecommendation: recordingVM.bluetoothRecommendation,
211→            systemAudioPermitted: recordingVM.systemAudioPermitted,
212→            recordingState: recordingVM.recordingState,
213→            diagnostics: recordingVM.debugDiagnostics,
214→            onCheckHealth: {
