/// Check that the Pablo backend is reachable. Unauthenticated.
pub async fn health_check(base_url: String) -> Result<(), PabloError> {
    let client = ApiClient::new(base_url);

    let response =
        client
            .get_public("/health")
            .send()
            .await
            .map_err(|e| PabloError::ApiClient {
                status_code: 0,
                message: e.to_string(),
            })?;

    if !response.status().is_success() {
        return Err(handle_error_response(response).await);
    }

    Ok(())
}

/// Fetch a paginated list of patients, optionally filtered by search term.
pub async fn fetch_patients(
    base_url: String,
    token: String,
    search: Option<String>,
    page: u32,
    page_size: u32,
) -> Result<PatientListResponse, PabloError> {
    let client = ApiClient::new(base_url);
    let token = SecretString::from(token);

    let mut query_params: Vec<(&str, String)> = vec![
        ("page", page.to_string()),
        ("page_size", page_size.to_string()),
    ];
    if let Some(ref s) = search {
        query_params.push(("search", s.clone()));
    }

    let response = client
        .get("/api/patients", &token)
        .query(&query_params)
        .send()
        .await
        .map_err(|e| PabloError::ApiClient {
            status_code: 0,
            message: e.to_string(),
        })?;

    if !response.status().is_success() {
        return Err(handle_error_response(response).await);
    }

    response
        .json::<PatientListResponse>()
        .await
        .map_err(|e| PabloError::JsonParse {
            message: e.to_string(),
        })
}

/// Upload a recording file to the backend via multipart form data.
pub async fn upload_recording(
    base_url: String,
    token: String,
    file_path: String,
) -> Result<UploadResponse, PabloError> {
    let client = ApiClient::new(base_url);
    let token = SecretString::from(token);

    let file_bytes = tokio::fs::read(&file_path)
        .await
        .map_err(|e| PabloError::ApiClient {
            status_code: 0,
            message: format!("Failed to read file: {e}"),
        })?;

    let file_name = std::path::Path::new(&file_path)
        .file_name()
        .unwrap_or_default()
        .to_string_lossy()
        .to_string();

    let part = reqwest::multipart::Part::bytes(file_bytes)
        .file_name(file_name)
        .mime_str("application/octet-stream")
        .map_err(|e| PabloError::ApiClient {
            status_code: 0,
            message: e.to_string(),
        })?;

    let form = reqwest::multipart::Form::new().part("file", part);

    let response = client
        .post("/api/recordings/upload", &token)
        .multipart(form)
        .send()
        .await
        .map_err(|e| PabloError::ApiClient {
            status_code: 0,
            message: e.to_string(),
        })?;

    if !response.status().is_success() {
        return Err(handle_error_response(response).await);
    }

    response
        .json::<UploadResponse>()
        .await
        .map_err(|e| PabloError::JsonParse {
            message: e.to_string(),
        })
}

